91	export interface ClaimResult {
92	  payout: number;
93	}
94	
95	const DEDUCTIBLE = 100;
96	const HALF_REIMBURSEMENT_ENCHANTMENT_THRESHOLD = 8;
97	const HALF_REIMBURSEMENT_RATE = 0.5;
98	
99	function payoutForDamage(damage: Damage, policy: QuoteResult): number {
100	  const damagedItem = policy.items.find((item) => item.type === damage.itemType);
101	  const halfReimbursementApplies =
102	    (damagedItem?.enchantment ?? 0) >= HALF_REIMBURSEMENT_ENCHANTMENT_THRESHOLD;
103	  const reimbursed = halfReimbursementApplies
104	    ? damage.amount * HALF_REIMBURSEMENT_RATE
105	    : damage.amount;
106	  return reimbursed - DEDUCTIBLE;
107	}
108	
109	export function claim(policy: QuoteResult, incident: Incident): ClaimResult {
110	  const payout = incident.damages.reduce(
111	    (total, damage) => total + payoutForDamage(damage, policy),
112	    0,
113	  );
114	  return { payout };
115	}
